def _AND():
  #[a b T] -> [a b a&b]
  qc = QuantumCircuit(3)
  qc.cx(0, 2)
  qc.cx(1, 2)
  qc.cx(2, [0,1])
  qc.tdg([0,1])
  qc.t(2)
  qc.cx(2, [0,1])
  qc.h(2)
  qc.s(2)
  return qc.to_gate(label='ADD')

def _ANDdg():
  #[a b a&b] -> [a b 0]
  qc = QuantumCircuit(3,1)
  qc.h(2)
  qc.measure(2,0)
  with qc.if_test((0, 1)):
    qc.cz(0, 1)
    qc.x(2)
  return qc

