def _convertToBits(i, padding=0):
  #returns padded list of bits in big-endian
  i_bitstr = bin(i)[2:]
  return [int(i) for i in i_bitstr[::-1]]+[0 for i in range(padding-len(i_bitstr))]

#base cases for size=1,2,3 must be done by hand
#luckily, these cases are simple
def _ConstantAdder_Size1(constant):
  a = _convertToBits(constant,1)
  qc = QuantumCircuit(1)
  if a[0] == 1:
    qc.x(0)
  return qc

def _ConstantAdder_Size2(constant):
  a = _convertToBits(constant,2)
  qc = QuantumCircuit(2)
  if a[1] == 1:
    qc.x(1)
  qc.cx(0,1)
  if a[0] == 1:
    qc.x(0)
  return qc

def _ConstantAdder_Size3(constant):
  a = _convertToBits(constant,3)
  qc = QuantumCircuit(3)
  if a[1] == 1:
    qc.x(0)
    qc.x(1)
  qc.mcx([0,1], 2)
  if a[1] == 1:
    qc.x(0)
  qc.cx(0,1)
  if a[0] == 1:
    qc.x(0)
  if a[2]+a[1] == 1: #XOR
    qc.x(2)
  return qc

