def _ControlledAdderBlock(constant_bit):
  qc = QuantumCircuit(4)
  if constant_bit:
    qc.x(1)
    qc.cx(0,2)
  qc.append(_AND(), [1,2,3])
  if constant_bit:
    qc.x(3)
  return qc.to_gate(label='add_block')


def _ControlledAdderBlockUncompute_op(constant_bit):
  qc = QuantumCircuit(4, 1)
  if constant_bit:
    qc.x(3)
  qc.compose(_ANDdg(), qubits=[1,2,3], clbits=[0], inplace=True)
  if constant_bit:
    qc.x(1)
  qc.mcx([0,1],2)

  return qc

