def _Controlled_ConstantAdder_SizeN(constant, size):
  a = _convertToBits(constant, size)

  control = [0]
  b = [1+i for i in range(0,size)]
  ancilla = [1+size+i for i in range(0,size-2)]
  qc = QuantumCircuit(2*size-1, 1)

  qc.h(ancilla)
  qc.t(ancilla)

  if a[1] == 1:
    qc.cx(control[0], b[0])
    qc.cx(control[0], b[1])
  qc.compose(_AND(), qubits=[b[0],b[1],ancilla[0]], inplace=True)
  if a[1] == 1:
    qc.x(ancilla[0])

  for i in range(1,size-2):
    qc.compose(_ControlledAdderBlock(a[i+1]), qubits=[control[0],ancilla[i-1], b[i+1], ancilla[i]],inplace=True)

  if a[-2] == 1:
    qc.x(ancilla[-1])
  qc.mcx([control[0], ancilla[-1]], b[-1])
  if a[-2] == 1:
    qc.x(ancilla[-1])
  for i in range(1,size-2)[::-1]:
    qc.compose(_ControlledAdderBlockUncompute_op(a[i+1]), qubits=[control[0], ancilla[i-1], b[i+1], ancilla[i]], clbits=[0], inplace=True)

  if a[1] == 1:
    qc.x(ancilla[0])
  qc.compose(_ANDdg(), qubits=[b[0],b[1],ancilla[0]], clbits=[0], inplace=True)
  if a[1] == 1:
    qc.cx(control[0], b[0])
  qc.mcx([control[0],b[0]], b[1])

  if a[-1]+a[-2]==1:
    qc.cx(control[0],b[-1])
  if a[0]==1:
    qc.cx(control[0],b[0])

  return qc

